// Loop over input items and add a new field called 'myNewField' to the JSON of each one
// 1. Lấy đường dẫn Video đã upload (giả sử lấy từ node Upload Video)
const videoPath =$('Retrieve Uploaded Video').first().json.file_info.file_path ; 

// 2. Lấy danh sách nhạc từ node Aggregate
const songs = $input.first().json.file_path; 

// 3. Tạo inputs: Video đứng đầu (index 0), sau đó là các bài nhạc
const apiInputs = [
  {
    file_path: videoPath,
    options: ["-stream_loop", "-1"] // Lặp lại video vô hạn cho đến khi hết nhạc
  },
  ...songs.map(path => ({ file_path: path }))
];

// 4. Tạo chuỗi filter concat audio (bắt đầu từ index 1 vì index 0 là video)
let audioNodes = "";
for (let i = 1; i <= songs.length; i++) {
  audioNodes += `[${i}:a]`;
}
const filterComplex = `${audioNodes}concat=n=${songs.length}:v=0:a=1[aout]`;

return {
  ffmpeg_job: {
    task: {
      inputs: apiInputs,
      filter_complex: filterComplex,
      outputs: [
        {
          file: "final_sleep_music_video.mp4",
          options: [
            "-map", "0:v:0",  // Lấy hình ảnh từ video nền
            "-map", "[aout]", // Lấy âm thanh đã nối
            "-c:v", "libx264",
            "-preset", "veryfast",
            "-shortest"       // Tự động dừng khi nhạc kết thúc (~22 phút)
          ]
        }
      ]
    }
  }
};

